Here's a modern MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static DataFetcher CreateFetcher(HttpMessageHandler handler)
        => new(new HttpClient(handler));

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        var fetcher = CreateFetcher(handler);

        // Act
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = CreateFetcher(handler);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange — handler that delays forever
        var handler = new FakeHandler(tcs: new TaskCompletionSource<HttpResponseMessage>());
        var fetcher = CreateFetcher(handler);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_TimeoutExpires_IsCancelledCooperatively()
    {
        // Arrange — handler that never completes; the [Timeout] fires
        // TestContext.CancellationToken and the test ends cleanly
        var handler = new FakeHandler(tcs: new TaskCompletionSource<HttpResponseMessage>());
        var fetcher = CreateFetcher(handler);

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    // Minimal fake handler — no mocking library needed
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage? _response;
        private readonly TaskCompletionSource<HttpResponseMessage>? _tcs;

        public FakeHandler(HttpResponseMessage response) => _response = response;
        public FakeHandler(TaskCompletionSource<HttpResponseMessage> tcs) => _tcs = tcs;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_tcs is not null)
            {
                // Wait indefinitely until cancelled
                await using (cancellationToken.Register(() => _tcs.TrySetCanceled(cancellationToken)))
                {
                    return await _tcs.Task;
                }
            }
            return _response!;
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly` field, satisfies nullability |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative cancellation — test ends cleanly on timeout instead of hanging |
| `Assert.ThrowsExactlyAsync<T>` | Verifies the exact exception type, replaces `[ExpectedException]` |
| `FakeHandler` | Controls `HttpClient` without mocking libraries; supports both instant and delayed responses |
| `sealed` class & helpers | Performance + design clarity |

The critical insight is the **timeout test**: by passing `TestContext.CancellationToken` into `FetchAsync`, the `[Timeout(3000)]` attribute fires that token, which propagates into `HttpClient.GetAsync`, causing a `TaskCanceledException`. Without this, a hung HTTP call would deadlock the test runner.
